        if (content === '[DOCUMENTO_PDF_VISUAL]') {
            console.log(`[PDF:PHASE:4:TOPOLOGY] INPUT -> ${JSON.stringify(fingerprint)}`);
        }

        const result = await StrategyEngine.process(
            file.name, 
            { __rawText: content, __source: 'file' }, 
            models, 
            globalKeywords
        );

        return {
